const scan = $input.first().json;
const chunks = (scan.ai_report_chunks && scan.ai_report_chunks.length > 0)
  ? scan.ai_report_chunks
  : (scan.ai_report_text ? [scan.ai_report_text] : ['Aucun rapport IA disponible.']);
const chatId = $('Telegram Bot (Unique)').item.json.callback_query.message.chat.id;

return chunks.map((text, i) => ({
  json: {
    ...scan,
    ai_report_text: text,
    telegram_chat_id: String(chatId),
    chunk_index: i + 1,
    chunk_total: chunks.length
  }
}));

